import AdminLayout from "../../AdminLayout";
import "./AddPatient.css";

export default function AddPatient() {
  return (
    <AdminLayout>
      <div className="patient-page">

        {/* Header */}
        <div className="patient-header">
          <h2>Patient Registration</h2>
          <span className="hl7">HL7 v2.5</span>
        </div>

        <div className="patient-card">

          {/* Patient Information */}
          <section className="card-section">
            <div className="section-header">
              <h3>Patient Information</h3>

              <div className="photo-upload">
                <div className="photo-box">
                  <span>Upload Photo</span>
                </div>
              </div>
            </div>

            <div className="grid">
              <div className="full">
                <label>Medical Record Number (MRN)</label>
                <input type="text" placeholder="MRN123" />
              </div>

              <div>
                <label>First Name</label>
                <input type="text" placeholder="John" />
              </div>

              <div>
                <label>Last Name</label>
                <input type="text" placeholder="Doe" />
              </div>

              <div>
                <label>Display Name</label>
                <input type="text" placeholder="John Doe" />
              </div>

              <div>
                <label>Date of Birth</label>
                <input type="date" />
              </div>

              <div>
                <label>Gender</label>
                <select>
                  <option>Male</option>
                  <option>Female</option>
                </select>
              </div>

              <div>
                <label>Marital Status</label>
                <select>
                  <option>Single</option>
                  <option>Married</option>
                </select>
              </div>

              <div className="full">
                <label>Age</label>
                <input type="text" placeholder="45" />
              </div>
            </div>
          </section>

          {/* Contact Details */}
          <section className="card-section">
            <h3>Contact Details</h3>

            <div className="grid">
              <div>
                <label>Address</label>
                <input type="text" placeholder="123 Main St" />
              </div>

              <div>
                <label>City</label>
                <select>
                  <option>Dubai</option>
                </select>
              </div>

              <div>
                <label>Country</label>
                <select>
                  <option>UAE</option>
                </select>
              </div>

              <div>
                <label>Mobile Number</label>
                <input type="text" placeholder="+971 050124567" />
              </div>
            </div>
          </section>

          {/* Patient Identification */}
          <section className="card-section">
            <div className="section-header">
              <h3>Patient Identification</h3>
              <span className="attach">Attach or Scan ID</span>
            </div>

            <div className="grid">
              <div>
                <label>ID Type</label>
                <select>
                  <option>Aadhar Card</option>
                </select>
              </div>

              <div>
                <label>National ID Number</label>
                <input type="text" placeholder="1234 5678 9012" />
              </div>

              <div>
                <label>Expiry Date</label>
                <input type="date" />
              </div>
            </div>
          </section>

          {/* Emergency Contact */}
          <section className="card-section">
            <h3>Emergency Contact</h3>

            <div className="grid">
              <div>
                <label>First Name</label>
                <input type="text" placeholder="Jane" />
              </div>

              <div>
                <label>Last Name</label>
                <input type="text" placeholder="Doe" />
              </div>

              <div className="full">
                <label>Mobile Number</label>
                <input type="text" placeholder="+971 0509876543" />
              </div>
            </div>
          </section>

          <div className="actions">
            <button className="submit">Register Patient</button>
          </div>

        </div>
      </div>
    </AdminLayout>
  );
